module top_module(
  input signed [7:0]       obf_a,
  input signed [10:0]      b,
  input signed [15:0]      c,
  input [1:0]              sel,
  output reg signed [15:0] res
  );always @* begin
    case(sel)
      0: res = obf_a + b;
      1: res = obf_a - b;
      2: res = obf_a + c;
      default: res = 16'bx;
    endcase
  end

endmodule
